                windowStart = characterIndexMap.get(rightMostCharacter) + 1;
            }
            // Update the last seen index of the current character.
            characterIndexMap.put(rightMostCharacter, windowEnd);
            // Calculate the current window size and update the maximum length found so far.
            maxLength = Math.max(maxLength, windowEnd - windowStart + 1);
        }
