    for (windowEnd, currentCharacter) in stringToExamine.enumerated() {
        // If the character is already in our map and its index is within the current window,
        // we need to move the start of the window.
        if let previousIndex = characterIndexes[currentCharacter], previousIndex >= windowStart {
            // This ensures the window only contains unique characters.
            windowStart = previousIndex + 1
        }
        // Update the last seen index of the current character.
        characterIndexes[currentCharacter] = windowEnd
        // Calculate the length of the current window and update maximum if necessary.
        let currentWindowLength = windowEnd - windowStart + 1
        maximumLength = max(maximumLength, currentWindowLength)
    }
